{
  "type": "FLIP_CARD",
  "lessonText": "Learn how to tune your guitar for the best sound.",
  "data": {
    "cards": [
      {
        "front": "What is standard tuning?",
        "back": "Standard tuning for a guitar is E-A-D-G-B-e.",
        "icon": "🎸"
      },
      {
        "front": "How do you use a tuner?",
        "back": "Clip on the tuner, pluck a string, and adjust until the needle is centered.",
        "icon": "📏"
      },
      {
        "front": "What is relative tuning?",
        "back": "Relative tuning involves tuning strings to each other, starting with one string as a reference.",
        "icon": "🔗"
      },
      {
        "front": "Why is tuning important?",
        "back": "Proper tuning ensures your guitar sounds harmonious and in tune with other instruments.",
        "icon": "🎶"
      }
    ]
  }
}
